/// Look up an icon glyph by name (case-insensitive; '_' and '-' equivalent).
pub fn icon_glyph(name: &str) -> Option<char> {
    let key = name.trim().to_ascii_lowercase().replace('_', "-");
    ICONS.binary_search_by(|(n, _)| n.cmp(&key.as_str())).ok().map(|i| ICONS[i].1)
}
